import type { CareerQuestion } from "./rrt-questions";

export const addictionsCounsellorQuestionsBatch3: CareerQuestion[] = [
  { id: "cac-601", stem: "A client diagnosed with antisocial personality disorder and alcohol use disorder frequently lies about their substance use. The counselor should:", options: ["Maintain non-judgmental engagement while using objective measures like drug testing to monitor progress","Refuse to continue treating the client due to dishonesty","Accept all client reports at face value","Confront aggressively to break through manipulation"], correctIndex: 0, rationale: "Personality disorders complicate treatment but are not contraindications. Non-judgmental engagement combined with objective measures maintains the therapeutic relationship while ensuring accurate assessment.", difficulty: 3, category: "Co-Occurring Disorders", topic: "Personality Disorders" },
  { id: "cac-602", stem: "Which neurotransmitter is MOST depleted following chronic methamphetamine use, contributing to anhedonia during early recovery?", options: ["Dopamine","Acetylcholine","Histamine","Glycine"], correctIndex: 0, rationale: "Methamphetamine causes massive dopamine release and eventual depletion through neurotoxic effects on dopaminergic neurons. This results in profound anhedonia that can persist for months during recovery.", difficulty: 3, category: "Theories of Addiction", topic: "Neurobiology" },
  { id: "cac-603", stem: "The DAST-10 (Drug Abuse Screening Test) is a validated tool used to:", options: ["Screen for drug use problems in the past 12 months using 10 yes/no questions","Diagnose specific substance use disorders","Determine medication dosages for treatment","Assess cognitive functioning in substance users"], correctIndex: 0, rationale: "The DAST-10 is a brief, self-administered screening instrument with 10 yes/no questions about drug use in the past year. Scores of 3+ suggest moderate-to-severe drug-related problems.", difficulty: 2, category: "Clinical Assessment", topic: "Screening Tools" },
  { id: "cac-604", stem: "When a client in recovery experiences a significant life stressor such as job loss, the counselor should prioritize:", options: ["Reinforcing coping skills and reviewing the relapse prevention plan while providing emotional support","Minimizing the stressor to keep the client focused on sobriety","Recommending immediate return to inpatient care","Suggesting the client take a break from recovery activities"], correctIndex: 0, rationale: "Life stressors are high-risk situations for relapse. Activating learned coping skills, reviewing the prevention plan, and enhancing social support during stressful periods strengthens recovery resilience.", difficulty: 2, category: "Relapse Prevention", topic: "Stress Management" },
  { id: "cac-605", stem: "Gabapentin is sometimes used off-label in addiction treatment primarily to:", options: ["Manage alcohol withdrawal symptoms and reduce cravings in alcohol use disorder","Serve as a substitute for opioids in maintenance treatment","Treat stimulant intoxication acutely","Reverse benzodiazepine overdose"], correctIndex: 0, rationale: "Gabapentin modulates calcium channels and may enhance GABA function. Clinical trials show efficacy in reducing alcohol cravings, improving sleep, and managing mild-to-moderate alcohol withdrawal.", difficulty: 4, category: "Pharmacology", topic: "Adjunctive Medications" },
  { id: "cac-606", stem: "In a family therapy session, the counselor observes that the mother consistently makes excuses for her adult son's drinking. This dynamic is BEST described as:", options: ["Codependency characterized by enabling behaviors that maintain the family system's homeostasis","Appropriate parental concern","A healthy coping mechanism","Effective family communication"], correctIndex: 0, rationale: "Codependency involves excessive emotional reliance and enabling behaviors that maintain dysfunction. The family system adapts around the addiction, with members taking on roles that paradoxically sustain it.", difficulty: 2, category: "Family Therapy", topic: "Family Roles" },
  { id: "cac-607", stem: "A counselor is leading a relapse prevention group and a member says, 'I've been clean for 2 years, so I can probably handle having one beer at a barbecue.' This cognitive distortion is BEST identified as:", options: ["Overconfidence bias and rationalization that underestimates ongoing vulnerability","A realistic and healthy assessment of recovery progress","An example of positive self-efficacy","Evidence of successful treatment completion"], correctIndex: 0, rationale: "Overconfidence in one's ability to control use is a common cognitive distortion in recovery. 'Testing control' or 'just one' thinking often precedes relapse, especially in seemingly low-risk situations.", difficulty: 2, category: "Relapse Prevention", topic: "Cognitive Distortions" },
  { id: "cac-608", stem: "The term 'dual diagnosis' in addiction counseling MOST commonly refers to:", options: ["Co-occurring substance use disorder and mental health disorder","Two different substance addictions occurring simultaneously","Diagnosis by two different clinicians","A primary and secondary medical diagnosis"], correctIndex: 0, rationale: "Dual diagnosis refers to the co-occurrence of at least one substance use disorder and at least one mental health disorder. Approximately 50% of individuals with SUD also have a mental health condition.", difficulty: 1, category: "Co-Occurring Disorders", topic: "Definitions" },
  { id: "cac-609", stem: "When a counselor uses the technique of 'developing discrepancy' in MI, they are:", options: ["Helping the client see the gap between their current behavior and their stated values or goals","Creating conflict between the client and their family","Pointing out inconsistencies in the client's story to catch them in lies","Emphasizing the difference between the client and other successful clients"], correctIndex: 0, rationale: "Developing discrepancy is a core MI strategy where the counselor helps the client explore the contradiction between their current substance use behavior and their deeper values, goals, and self-image.", difficulty: 2, category: "Motivational Interviewing", topic: "Core Strategies" },
  { id: "cac-610", stem: "A client prescribed Vivitrol (extended-release naltrexone injection) must be opioid-free for a minimum of:", options: ["7-10 days before the first injection to avoid precipitated withdrawal","24 hours","No waiting period is required","30 days"], correctIndex: 0, rationale: "Patients must be opioid-free for 7-10 days (7 days for short-acting, 10-14 for long-acting opioids) before naltrexone to avoid precipitated withdrawal. A naloxone challenge test may be performed.", difficulty: 3, category: "Pharmacology", topic: "Medication-Assisted Treatment" },
  { id: "cac-611", stem: "The concept of 'powerlessness' in the first step of Alcoholics Anonymous refers to:", options: ["The recognition that one cannot control their drinking once they start","Complete helplessness in all areas of life","An inability to make any decisions","A requirement to give up all personal autonomy"], correctIndex: 0, rationale: "Step 1 powerlessness specifically refers to the inability to control substance use. It acknowledges the loss of control over drinking/using, not powerlessness over life in general.", difficulty: 1, category: "Treatment Modalities", topic: "Twelve-Step Programs" },
  { id: "cac-612", stem: "A counselor notices that they are becoming increasingly emotionally exhausted, cynical about clients' ability to recover, and less effective in sessions. This pattern is MOST consistent with:", options: ["Professional burnout requiring self-care, supervision, and possible workload adjustment","Normal progression in any counseling career","An indication to leave the profession permanently","A personal relapse in the counselor's own recovery"], correctIndex: 0, rationale: "Burnout involves emotional exhaustion, depersonalization (cynicism), and reduced personal accomplishment. Prevention includes regular supervision, self-care practices, manageable caseloads, and peer support.", difficulty: 1, category: "Ethics", topic: "Self-Care" },
  { id: "cac-613", stem: "Synthetic cannabinoids (e.g., K2, Spice) differ from natural cannabis in that they:", options: ["Are often more potent full agonists at cannabinoid receptors, causing more severe adverse effects","Are safer because they are synthetically produced","Produce identical effects to natural cannabis","Are FDA-approved for medical use"], correctIndex: 0, rationale: "Synthetic cannabinoids are full CB1 agonists (versus THC's partial agonism), often 10-200x more potent. They cause severe adverse effects including psychosis, seizures, cardiovascular events, and death.", difficulty: 3, category: "Substance Use Disorders", topic: "Emerging Substances" },
  { id: "cac-614", stem: "In the context of motivational interviewing, 'sustain talk' refers to:", options: ["Client statements that favor maintaining the status quo and not changing substance use behavior","The counselor's arguments for why the client should keep using","Supportive statements from the client's family","Technical documentation language"], correctIndex: 0, rationale: "Sustain talk includes client statements expressing desire to continue use, inability to change, reasons for continuing, or lack of need for change. MI counselors avoid reinforcing sustain talk.", difficulty: 2, category: "Motivational Interviewing", topic: "Sustain Talk" },
  { id: "cac-615", stem: "A counselor working with veterans should be aware that military culture:", options: ["May emphasize self-reliance and stigmatize help-seeking, creating barriers to treatment engagement","Has no impact on treatment approaches","Encourages open discussion of emotional vulnerability","Is identical across all branches and eras of service"], correctIndex: 0, rationale: "Military culture values strength, self-reliance, and mission focus. These values, while adaptive in service, may create barriers to seeking help. Counselors should frame treatment in culturally resonant terms.", difficulty: 2, category: "Cultural Competence", topic: "Military/Veterans" },
  { id: "cac-616", stem: "The process of 'titration' in medication-assisted treatment refers to:", options: ["Gradually adjusting medication dosage to achieve optimal therapeutic effect with minimal side effects","Abruptly stopping medication","Combining multiple medications simultaneously","Testing blood levels of a substance"], correctIndex: 0, rationale: "Titration involves carefully increasing (or decreasing) medication doses over time to find the optimal therapeutic level. This applies to methadone induction, buprenorphine dosing, and psychiatric medications.", difficulty: 2, category: "Pharmacology", topic: "Dosing Principles" },
  { id: "cac-617", stem: "A client in a 28-day residential program requests discharge against medical advice on day 5. The counselor should:", options: ["Explore the client's reasons, discuss risks, ensure safety planning, and document informed consent for AMA discharge","Physically prevent the client from leaving","Immediately discharge the client without discussion","Threaten loss of all future treatment access"], correctIndex: 0, rationale: "Clients have the right to leave treatment. The counselor should explore reasons, address concerns, discuss risks of premature discharge, develop a safety plan, and document the AMA discussion.", difficulty: 2, category: "Ethics", topic: "Client Rights" },
  { id: "cac-618", stem: "Research on the genetics of addiction suggests that genetic factors account for approximately what percentage of vulnerability to developing substance use disorders?", options: ["40-60%","10-15%","90-95%","Less than 5%"], correctIndex: 0, rationale: "Twin, adoption, and family studies consistently show that genetic factors account for 40-60% of vulnerability to addiction. Environmental factors and gene-environment interactions account for the remainder.", difficulty: 3, category: "Theories of Addiction", topic: "Genetics" },
  { id: "cac-619", stem: "In group therapy, 'universality' as a therapeutic factor refers to:", options: ["The experience of realizing that others share similar problems and feelings, reducing isolation","A therapy technique used by all counselors universally","The belief that one treatment works for all clients","A group rule that everyone must participate equally"], correctIndex: 0, rationale: "Universality (Yalom's therapeutic factor) occurs when group members discover that others share similar experiences, reducing shame and isolation. This is particularly powerful in addiction treatment groups.", difficulty: 2, category: "Group Therapy", topic: "Therapeutic Factors" },
  { id: "cac-620", stem: "A client reports regularly using energy drinks containing high doses of caffeine along with alcohol. The counselor should educate the client that:", options: ["Caffeine masks the sedating effects of alcohol, leading to increased consumption and higher risk of alcohol-related harm","Caffeine neutralizes the harmful effects of alcohol","This combination is generally considered safe","Energy drinks help the body metabolize alcohol faster"], correctIndex: 0, rationale: "Caffeine's stimulant effects mask alcohol's sedation, leading to 'wide-awake drunk' states where individuals consume more alcohol and engage in riskier behaviors while feeling less impaired.", difficulty: 2, category: "Substance Use Disorders", topic: "Drug Interactions" },
  { id: "cac-621", stem: "The primary purpose of a treatment plan in addiction counseling is to:", options: ["Establish measurable, client-centered goals with specific interventions and timeframes","Satisfy administrative requirements without clinical utility","Document the counselor's theoretical orientation","Provide a legal defense against malpractice claims"], correctIndex: 0, rationale: "Treatment plans are living clinical documents that guide treatment with specific, measurable, achievable, relevant, and time-bound (SMART) goals developed collaboratively with the client.", difficulty: 1, category: "Counseling Fundamentals", topic: "Treatment Planning" },
  { id: "cac-622", stem: "Prolonged QT interval is a cardiac risk associated with which medication used in addiction treatment?", options: ["Methadone, especially at higher doses","Buprenorphine at standard doses","Naltrexone oral tablets","Acamprosate"], correctIndex: 0, rationale: "Methadone can prolong the QT interval in a dose-dependent manner, increasing risk of torsades de pointes. ECG monitoring is recommended, particularly at doses above 100mg/day or with other QT-prolonging medications.", difficulty: 4, category: "Pharmacology", topic: "Adverse Effects" },
  { id: "cac-623", stem: "A counselor working with a client who has both substance use disorder and an eating disorder should recognize that:", options: ["Both conditions involve dysregulated reward circuitry and may share common risk factors and treatment targets","Eating disorders and substance use disorders never co-occur","Treating one condition will automatically resolve the other","These conditions require completely separate treatment teams with no coordination"], correctIndex: 0, rationale: "SUDs and eating disorders share neurobiological (reward pathway), psychological (affect regulation), and risk factors. Integrated treatment addressing both conditions' shared underlying mechanisms is recommended.", difficulty: 3, category: "Co-Occurring Disorders", topic: "Eating Disorders" },
  { id: "cac-624", stem: "The ethical principle of 'beneficence' in addiction counseling means:", options: ["Acting in the best interest of the client and promoting their well-being","Doing no harm to the client","Maintaining client confidentiality at all times","Treating all clients equally regardless of background"], correctIndex: 0, rationale: "Beneficence is the ethical obligation to promote the client's well-being and act in their best interest. It is distinct from nonmaleficence (do no harm) though both guide ethical practice.", difficulty: 1, category: "Ethics", topic: "Ethical Principles" },
  { id: "cac-625", stem: "A client in early recovery reports vivid, disturbing dreams about using drugs. The counselor should:", options: ["Normalize this experience as common in early recovery and explore any feelings or insights the dreams may reveal","Interpret the dreams as evidence of imminent relapse","Refer immediately for psychiatric evaluation","Recommend sleeping medication to prevent the dreams"], correctIndex: 0, rationale: "Using dreams are extremely common in early recovery as the brain processes the absence of substances. Normalizing them reduces anxiety, and exploring them can provide insight into recovery challenges.", difficulty: 2, category: "Counseling Fundamentals", topic: "Early Recovery" },
  { id: "cac-626", stem: "Which population has the highest rate of binge drinking and alcohol use disorders in the United States?", options: ["Young adults ages 18-25","Adults over 65","Children under 12","Adults ages 45-55"], correctIndex: 0, rationale: "Epidemiological data consistently shows that young adults ages 18-25 have the highest rates of binge drinking, heavy alcohol use, and alcohol use disorders, coinciding with developmental and social factors.", difficulty: 1, category: "Substance Use Disorders", topic: "Epidemiology" },
  { id: "cac-627", stem: "A counselor facilitating a process group notices that one member dominates every discussion while others remain silent. The MOST effective intervention is:", options: ["Gently redirect the dominant member while inviting quieter members to share their perspectives","Allow the pattern to continue without intervention","Remove the dominant member from the group","Only address the issue in individual sessions, never in group"], correctIndex: 0, rationale: "Addressing group dynamics in the moment is essential for effective group facilitation. Redirecting dominance while creating space for quieter members maintains group cohesion and therapeutic benefit for all.", difficulty: 2, category: "Group Therapy", topic: "Facilitation Skills" },
  { id: "cac-628", stem: "Inhalant use disorder is particularly concerning in adolescents because:", options: ["Inhalants can cause sudden sniffing death syndrome from cardiac arrhythmia even on first use","Inhalants have no long-term neurological effects","Adolescents are physiologically immune to inhalant toxicity","Inhalants are only dangerous when used chronically for years"], correctIndex: 0, rationale: "Sudden sniffing death can occur from cardiac arrhythmia (sensitization of the myocardium to catecholamines) even during first use. Chronic use causes irreversible neurological damage and organ toxicity.", difficulty: 2, category: "Substance Use Disorders", topic: "Inhalants" },
  { id: "cac-629", stem: "The term 'iatrogenic addiction' refers to:", options: ["Addiction that develops as a result of medical treatment, such as prescribed opioid analgesics","Addiction caused by genetic factors","Self-medication for untreated mental illness","Addiction that develops during incarceration"], correctIndex: 0, rationale: "Iatrogenic addiction results from medical interventions, most commonly long-term prescription of opioid analgesics for pain. Recognition of this phenomenon contributed to re-evaluation of opioid prescribing practices.", difficulty: 2, category: "Substance Use Disorders", topic: "Prescription Drug Misuse" },
  { id: "cac-630", stem: "A client states they use alcohol to manage social anxiety. This pattern is BEST described as:", options: ["Self-medication, using a substance to manage symptoms of an underlying condition","Recreational use","Experimental use","Social drinking within normal limits"], correctIndex: 0, rationale: "Self-medication hypothesis (Khantzian) proposes that individuals use substances to relieve or manage psychiatric symptoms. Identifying the underlying condition enables integrated treatment planning.", difficulty: 1, category: "Co-Occurring Disorders", topic: "Self-Medication" },
  { id: "cac-631", stem: "The therapeutic community model was pioneered by:", options: ["Charles Dederich at Synanon, later refined by George De Leon and others","Sigmund Freud in Vienna","Bill Wilson and Dr. Bob Smith","B.F. Skinner in behavioral laboratories"], correctIndex: 0, rationale: "Synanon (1958) was the first drug-free therapeutic community. George De Leon later developed the evidence base and refined the model into the modern therapeutic community approach used worldwide.", difficulty: 3, category: "Treatment Modalities", topic: "History" },
  { id: "cac-632", stem: "When assessing suicide risk in a client with substance use disorder, which factor MOST significantly increases acute risk?", options: ["Active intoxication combined with access to lethal means and a specific plan","Chronic substance use without recent changes","Stable housing and employment","Regular attendance at treatment sessions"], correctIndex: 0, rationale: "Active intoxication lowers inhibitions and impairs judgment. Combined with access to means and a specific plan, this represents the highest acute suicide risk requiring immediate safety intervention.", difficulty: 2, category: "Crisis Intervention", topic: "Suicide Risk Assessment" },
  { id: "cac-633", stem: "In the pre-contemplation stage, the MOST appropriate counseling strategy is:", options: ["Raise awareness and provide personalized feedback about risks without pressuring change","Develop a detailed action plan with specific behavior change goals","Focus on relapse prevention strategies","Assign homework related to maintaining sobriety"], correctIndex: 0, rationale: "In pre-contemplation, clients don't yet see their use as problematic. Raising awareness through reflective listening, providing objective feedback, and planting seeds of doubt is most stage-appropriate.", difficulty: 2, category: "Theories of Addiction", topic: "Stage-Matched Intervention" },
  { id: "cac-634", stem: "Clonidine is sometimes used in opioid detoxification because it:", options: ["Reduces autonomic symptoms of withdrawal such as anxiety, sweating, and elevated blood pressure by acting on alpha-2 adrenergic receptors","Is a full opioid agonist that replaces heroin","Blocks all opioid receptors preventing any opioid effects","Accelerates the metabolism of opioids in the body"], correctIndex: 0, rationale: "Clonidine is an alpha-2 adrenergic agonist that reduces noradrenergic hyperactivity during opioid withdrawal, alleviating symptoms like anxiety, sweating, muscle aches, and hypertension.", difficulty: 3, category: "Pharmacology", topic: "Detoxification Medications" },
  { id: "cac-635", stem: "A client who is a nurse reports diverting medications at work. In addition to addressing the substance use disorder, the counselor must:", options: ["Follow applicable reporting requirements to the state nursing board and ensure workplace safety concerns are addressed","Keep this information completely confidential under all circumstances","Report only to the client's employer","Ignore the workplace issue and focus solely on personal recovery"], correctIndex: 0, rationale: "Healthcare workers diverting medications pose patient safety risks. Most states have mandatory reporting to licensing boards. Many boards offer alternative-to-discipline programs that support recovery while protecting public safety.", difficulty: 3, category: "Ethics", topic: "Mandated Reporting" },
  { id: "cac-636", stem: "The CRAFFT screening tool is specifically designed for use with:", options: ["Adolescents to screen for substance use-related risks","Elderly populations for prescription medication misuse","Pregnant women for alcohol use","Healthcare professionals for impairment"], correctIndex: 0, rationale: "CRAFFT (Car, Relax, Alone, Forget, Friends, Trouble) is a validated 6-item screening tool designed specifically for adolescents ages 12-21 to identify high-risk alcohol and drug use.", difficulty: 2, category: "Clinical Assessment", topic: "Screening Tools" },
  { id: "cac-637", stem: "A client reports using poppy seed tea purchased online. The counselor should be aware that:", options: ["Unwashed poppy seeds contain variable amounts of morphine and codeine, posing overdose and dependence risks","Poppy seed tea contains no active opioid compounds","This is a safe alternative to pharmaceutical opioids","Poppy seed tea cannot cause physical dependence"], correctIndex: 0, rationale: "Unwashed poppy seeds contain morphine, codeine, and thebaine in highly variable concentrations. Multiple deaths have been reported from poppy seed tea due to unpredictable potency and overdose risk.", difficulty: 3, category: "Substance Use Disorders", topic: "Emerging Substances" },
  { id: "cac-638", stem: "Which type of group therapy focuses on teaching specific skills such as anger management, communication, and problem-solving?", options: ["Psychoeducational group","Process group","Support group","Encounter group"], correctIndex: 0, rationale: "Psychoeducational groups are structured around skill development and information delivery. They teach specific content (anger management, relapse prevention skills) using didactic and interactive methods.", difficulty: 1, category: "Group Therapy", topic: "Group Types" },
  { id: "cac-639", stem: "When documenting in a client's record, the counselor should:", options: ["Use objective, behaviorally specific language that supports clinical observations and treatment decisions","Include personal opinions about the client's character","Use vague language to protect confidentiality","Document only positive progress to maintain client morale"], correctIndex: 0, rationale: "Documentation should be objective, specific, clinically relevant, and timely. It should describe observable behaviors, interventions used, client responses, and progress toward treatment plan goals.", difficulty: 1, category: "Counseling Fundamentals", topic: "Documentation" },
  { id: "cac-640", stem: "A client with 5 years of sobriety returns to treatment reporting increased cravings. Assessment reveals a recent traumatic event. This scenario illustrates:", options: ["Trauma can destabilize recovery at any point, highlighting the need for ongoing trauma-informed support","That 5 years of sobriety means treatment has failed","Cravings only occur in early recovery","The client's original treatment was inadequate"], correctIndex: 0, rationale: "Recovery is a lifelong process, and new stressors, particularly trauma, can activate cravings even after extended sobriety. This underscores the chronic nature of addiction and the value of ongoing support.", difficulty: 2, category: "Relapse Prevention", topic: "Long-Term Recovery" },
  { id: "cac-641", stem: "Phenobarbital is sometimes used in alcohol detoxification protocols as an alternative to benzodiazepines because:", options: ["It has a long half-life providing stable blood levels and smoother withdrawal management","It has no sedative properties","It is not a controlled substance","It works by blocking dopamine receptors"], correctIndex: 0, rationale: "Phenobarbital's long half-life (53-118 hours) provides self-tapering properties and stable blood levels. Some protocols prefer it over benzodiazepines due to lower abuse potential and consistent pharmacokinetics.", difficulty: 4, category: "Pharmacology", topic: "Detoxification Medications" },
  { id: "cac-642", stem: "The concept of 'stages of group development' is important because:", options: ["Understanding group stages helps the counselor adjust facilitation strategies appropriately at each phase","Groups never experience predictable developmental patterns","Only the final stage of group development is therapeutically productive","Stage theory applies only to long-term psychotherapy groups"], correctIndex: 0, rationale: "Knowing that groups progress through forming, storming, norming, performing, and adjourning allows counselors to normalize group dynamics and adapt their leadership style to the group's developmental needs.", difficulty: 2, category: "Group Therapy", topic: "Group Development" },
  { id: "cac-643", stem: "A counselor working with a client who identifies as transgender should:", options: ["Use the client's preferred name and pronouns and address how gender-related stressors may relate to substance use","Insist on using the name and gender listed in medical records","Avoid discussing gender identity as it is irrelevant to addiction treatment","Refer to a gender specialist and discontinue addiction services"], correctIndex: 0, rationale: "Gender-affirming care includes using preferred name/pronouns and exploring how minority stress (discrimination, violence, rejection) may contribute to substance use. This improves engagement and outcomes.", difficulty: 2, category: "Cultural Competence", topic: "Gender Identity" },
  { id: "cac-644", stem: "The term 'progression' in addiction refers to:", options: ["The tendency for substance use disorders to become more severe over time without intervention","A positive step forward in recovery","Advancement in a counselor's career","The stages of treatment completion"], correctIndex: 0, rationale: "Progression describes how addiction typically worsens over time, involving increasing amounts, more frequent use, escalating consequences, and declining functioning, without intervention to interrupt the cycle.", difficulty: 1, category: "Theories of Addiction", topic: "Disease Model" },
  { id: "cac-645", stem: "When a client presents with both chronic pain and opioid use disorder, the treatment approach should:", options: ["Integrate pain management and addiction treatment, considering non-opioid and multimodal pain strategies","Prescribe high-dose opioids because pain management takes priority over addiction concerns","Refuse to address pain as it enables continued opioid use","Tell the client their pain is psychological and not real"], correctIndex: 0, rationale: "Integrated treatment addresses both conditions using multimodal pain management (non-opioid medications, physical therapy, CBT for pain) alongside addiction treatment, often including buprenorphine which treats both.", difficulty: 3, category: "Co-Occurring Disorders", topic: "Chronic Pain" },
  { id: "cac-646", stem: "In the harm reduction framework, the hierarchy of goals places which outcome as MOST important?", options: ["Keeping the person alive and reducing immediate life-threatening risks","Complete abstinence from all substances","Perfect compliance with treatment recommendations","Elimination of all drug-related behaviors"], correctIndex: 0, rationale: "Harm reduction prioritizes preservation of life. The hierarchy moves from reducing death and disease risk, to reducing substance-related harm, to moderation, to abstinence, meeting clients where they are.", difficulty: 2, category: "Treatment Modalities", topic: "Harm Reduction" },
  { id: "cac-647", stem: "Cognitive restructuring in addiction treatment involves:", options: ["Identifying and modifying irrational beliefs and automatic thoughts that contribute to substance use","Brain surgery to alter neural pathways","Forcing the client to think positively","Avoiding all discussions about thoughts and focusing only on behavior"], correctIndex: 0, rationale: "Cognitive restructuring systematically identifies cognitive distortions (permission-giving beliefs, catastrophizing, all-or-nothing thinking) and develops more balanced, adaptive thought patterns.", difficulty: 2, category: "Treatment Modalities", topic: "CBT Techniques" },
  { id: "cac-648", stem: "A counselor completing a discharge summary should include:", options: ["Presenting problem, treatment provided, progress toward goals, discharge status, continuing care recommendations, and prognosis","Only the client's name and discharge date","A detailed personal history of the counselor's experience with the client","Insurance billing information exclusively"], correctIndex: 0, rationale: "Discharge summaries provide continuity of care by documenting the treatment episode, client progress, discharge conditions, and aftercare recommendations for subsequent providers.", difficulty: 1, category: "Counseling Fundamentals", topic: "Documentation" },
  { id: "cac-649", stem: "The phenomenon where a person returns to substance use at their previous dose after a period of abstinence and experiences overdose is explained by:", options: ["Loss of tolerance during abstinence, making the previously tolerated dose now dangerous","Increased tolerance from not using","Improved liver function during abstinence","Psychological rather than physiological factors"], correctIndex: 0, rationale: "Tolerance diminishes during abstinence. Using at pre-abstinence doses can cause overdose because the body no longer has the neuroadaptations to handle that amount. This is a major cause of opioid overdose deaths.", difficulty: 2, category: "Substance Use Disorders", topic: "Tolerance and Overdose" },
  { id: "cac-650", stem: "Seeking Safety is an evidence-based treatment model designed for:", options: ["Clients with co-occurring PTSD and substance use disorders, focusing on present-oriented coping skills","Only clients with substance use disorders without trauma history","Exclusively inpatient psychiatric populations","Children under age 10 with behavioral problems"], correctIndex: 0, rationale: "Seeking Safety (Najavits) is a present-focused, manualized treatment for co-occurring PTSD and SUD. It teaches safe coping skills in cognitive, behavioral, and interpersonal domains without requiring trauma processing.", difficulty: 2, category: "Treatment Modalities", topic: "Trauma-Informed Treatment" },
  { id: "cac-651", stem: "A client reports using tianeptine (sold as 'gas station heroin'). The counselor should know that:", options: ["Tianeptine acts on mu-opioid receptors at high doses and can produce dependence and a withdrawal syndrome similar to opioid withdrawal","Tianeptine has no psychoactive effects","Tianeptine is FDA-approved for treating depression","Tianeptine cannot cause physical dependence"], correctIndex: 0, rationale: "Tianeptine at high doses activates mu-opioid receptors producing euphoria, dependence, and opioid-like withdrawal. It is sold in some US states as a supplement despite growing reports of abuse and ER visits.", difficulty: 4, category: "Substance Use Disorders", topic: "Emerging Substances" },
  { id: "cac-652", stem: "The counselor's role in a multidisciplinary treatment team includes:", options: ["Providing substance use disorder-specific expertise while collaborating with medical, psychiatric, and social service professionals","Making all treatment decisions independently without input from other team members","Prescribing medications within the counselor's scope of practice","Replacing the need for medical and psychiatric providers"], correctIndex: 0, rationale: "Addiction counselors contribute specialized SUD knowledge to multidisciplinary teams. Collaboration with physicians, psychiatrists, social workers, and case managers provides comprehensive, coordinated care.", difficulty: 1, category: "Counseling Fundamentals", topic: "Interdisciplinary Care" },
  { id: "cac-653", stem: "A client completing intensive outpatient treatment (IOP) should be transitioned to:", options: ["A less intensive level of care such as outpatient counseling with a continuing care plan","No further treatment since IOP is sufficient","Inpatient treatment regardless of progress","The same level of care indefinitely"], correctIndex: 0, rationale: "Step-down from IOP to standard outpatient maintains treatment engagement while supporting increasing independence. Continuing care plans should include self-help groups, individual counseling, and community resources.", difficulty: 1, category: "Clinical Assessment", topic: "Continuing Care" },
  { id: "cac-654", stem: "The 'Colombo technique' in motivational interviewing involves:", options: ["Playing a curious, slightly confused role to encourage the client to explain and elaborate on their thinking","Interrogating the client to find inconsistencies","Using silence exclusively throughout the session","Providing direct medical advice"], correctIndex: 0, rationale: "Named after the TV detective, this MI technique involves expressing genuine curiosity and asking the client to help the counselor understand, which encourages client elaboration and self-exploration.", difficulty: 3, category: "Motivational Interviewing", topic: "Advanced Techniques" },
  { id: "cac-655", stem: "Which laboratory test is MOST useful for monitoring chronic alcohol use over the preceding 2-4 weeks?", options: ["Carbohydrate-deficient transferrin (CDT)","Complete blood count","Basic metabolic panel","Urinalysis"], correctIndex: 0, rationale: "CDT is a specific biomarker for heavy alcohol use (>60g/day for 2+ weeks). It has high specificity and returns to normal with 2-4 weeks of abstinence, making it useful for monitoring.", difficulty: 3, category: "Clinical Assessment", topic: "Laboratory Monitoring" },
  { id: "cac-656", stem: "A counselor learns that a client has been selling their prescribed buprenorphine. The counselor should:", options: ["Address this clinically as a treatment compliance issue, assess reasons for diversion, and adjust the treatment plan including possible observed dosing","Ignore the behavior to maintain therapeutic alliance","Immediately discharge the client from all treatment","Report to law enforcement without addressing it clinically"], correctIndex: 0, rationale: "Medication diversion is a clinical issue requiring assessment (financial need? using other substances? inadequate dose?). Observed dosing, more frequent visits, and addressing underlying reasons is therapeutic.", difficulty: 3, category: "Ethics", topic: "Clinical Decision-Making" },
  { id: "cac-657", stem: "Acceptance and Commitment Therapy (ACT) in addiction treatment focuses on:", options: ["Psychological flexibility through acceptance, defusion from unhelpful thoughts, and committed action aligned with values","Rigidly controlling thoughts and emotions","Eliminating all negative thoughts and feelings","Analyzing childhood experiences extensively"], correctIndex: 0, rationale: "ACT promotes psychological flexibility through six core processes: acceptance, cognitive defusion, present moment awareness, self-as-context, values clarification, and committed action toward recovery goals.", difficulty: 3, category: "Treatment Modalities", topic: "ACT" },
  { id: "cac-658", stem: "When a client with substance use disorder presents to the emergency department with chest pain, the treatment team should be aware that:", options: ["Cocaine and methamphetamine can cause myocardial infarction even in young, otherwise healthy individuals","Substance use history is irrelevant to cardiac symptoms","Only alcohol affects the cardiovascular system","Stimulant-related chest pain is never a true emergency"], correctIndex: 0, rationale: "Stimulants cause coronary vasospasm, tachycardia, and hypertension leading to MI, aortic dissection, and arrhythmias regardless of age or cardiovascular risk factors. Complete substance history is essential.", difficulty: 2, category: "Substance Use Disorders", topic: "Medical Emergencies" },
  { id: "cac-659", stem: "The principle of 'informed consent' in addiction treatment requires that clients:", options: ["Receive clear information about the nature, risks, benefits, and alternatives to treatment before agreeing to participate","Simply sign a consent form without explanation","Agree to all treatment recommendations without question","Have a family member sign on their behalf"], correctIndex: 0, rationale: "Informed consent is an ongoing process requiring disclosure of treatment nature, expected benefits, risks, alternatives, confidentiality limits, and the right to withdraw. It supports client autonomy and dignity.", difficulty: 1, category: "Ethics", topic: "Client Rights" },
  { id: "cac-660", stem: "A counselor suspects a client is developing transfer addiction, switching from alcohol to gambling. The MOST appropriate response is:", options: ["Address the cross-addiction pattern directly, incorporate it into the treatment plan, and monitor for other behavioral addictions","Focus only on the original alcohol problem","Congratulate the client for not drinking","Refer to a gambling-specific program and discharge from current treatment"], correctIndex: 0, rationale: "Transfer or cross-addiction is common when underlying reward-seeking behavior is not addressed. Treatment should address the addiction process broadly, not just the specific substance or behavior.", difficulty: 3, category: "Behavioral Addictions", topic: "Cross-Addiction" },
  { id: "cac-661", stem: "The Community Reinforcement Approach (CRA) is based on the principle that:", options: ["Rearranging environmental contingencies so that a sober lifestyle is more rewarding than substance use","Removing the client from all community connections","Punishment is the most effective motivator for behavior change","Substance use is solely a moral choice"], correctIndex: 0, rationale: "CRA applies operant conditioning principles to make the natural environment more rewarding for sobriety. It addresses social, recreational, vocational, and family domains to build a reinforcing sober lifestyle.", difficulty: 3, category: "Treatment Modalities", topic: "Behavioral Interventions" },
  { id: "cac-662", stem: "A client with alcohol use disorder who is also taking acetaminophen regularly is at increased risk for:", options: ["Hepatotoxicity due to the combined effects of alcohol and acetaminophen on the liver","Improved liver function","No additional health risks","Kidney stone formation"], correctIndex: 0, rationale: "Both alcohol and acetaminophen are metabolized by the liver. Chronic alcohol use induces CYP2E1, increasing formation of the toxic NAPQI metabolite from acetaminophen, significantly raising hepatotoxicity risk.", difficulty: 3, category: "Pharmacology", topic: "Drug Interactions" },
  { id: "cac-663", stem: "In the ASAM criteria, Dimension 5 (Relapse, Continued Use, or Continued Problem Potential) assesses:", options: ["The client's historical pattern of relapse, current relapse potential, and ability to manage high-risk situations","Only the number of previous treatment episodes","Financial ability to pay for treatment","Geographic proximity to treatment facilities"], correctIndex: 0, rationale: "Dimension 5 evaluates relapse history, recognition of relapse triggers, availability of coping strategies, and the degree to which the client can manage situations that might lead to return to use.", difficulty: 2, category: "Clinical Assessment", topic: "ASAM Dimensions" },
  { id: "cac-664", stem: "When a counselor experiences value conflicts with a client's lifestyle choices, the MOST ethical response is:", options: ["Seek supervision and examine personal biases while continuing to provide competent, non-judgmental care","Impose personal values on the client","Terminate the therapeutic relationship immediately","Express disapproval to motivate the client to change"], correctIndex: 0, rationale: "Self-awareness of personal values and biases is essential. Supervision helps counselors process value conflicts while maintaining professional obligations to provide non-judgmental, competent care.", difficulty: 2, category: "Ethics", topic: "Values and Biases" },
  { id: "cac-665", stem: "A client reports using phenibut, a substance purchased online. The counselor should know that:", options: ["Phenibut is a GABA-B agonist that produces effects similar to alcohol and benzodiazepines, with potential for dependence and dangerous withdrawal","Phenibut is an FDA-approved dietary supplement with no risks","Phenibut has no psychoactive properties","Phenibut withdrawal is always mild and self-limiting"], correctIndex: 0, rationale: "Phenibut (β-phenyl-GABA) is a GABA-B agonist producing anxiolysis and euphoria. Physical dependence develops rapidly, and withdrawal can include severe anxiety, psychosis, and seizures similar to alcohol/benzo withdrawal.", difficulty: 4, category: "Substance Use Disorders", topic: "Emerging Substances" },
  { id: "cac-666", stem: "The primary difference between screening and comprehensive assessment in addiction treatment is:", options: ["Screening briefly identifies probable presence of a problem, while comprehensive assessment provides detailed diagnostic and treatment planning information","There is no difference between screening and assessment","Screening is more thorough than assessment","Assessment is only done at discharge, not at intake"], correctIndex: 0, rationale: "Screening is a brief process to identify individuals who may have substance use problems and need further evaluation. Comprehensive assessment is a detailed clinical process for diagnosis and individualized treatment planning.", difficulty: 1, category: "Clinical Assessment", topic: "Assessment Process" },
  { id: "cac-667", stem: "Contingency management studies show that the MOST effective reinforcement schedule for promoting abstinence is:", options: ["Escalating magnitude of reinforcement for consecutive negative drug tests with reset after positive test","Equal reinforcement regardless of consecutive negatives","Punishment for positive tests with no reward for negatives","Random reinforcement unrelated to drug test results"], correctIndex: 0, rationale: "Prize magnitude escalation with reset protocols produce the strongest outcomes. Increasing value of rewards for consecutive negative tests strengthens motivation, while reset after positive tests maintains contingency.", difficulty: 3, category: "Treatment Modalities", topic: "Contingency Management" },
  { id: "cac-668", stem: "When working with a client from a culture that views addiction as a spiritual problem, the counselor should:", options: ["Respect the cultural framework while integrating evidence-based treatments in a culturally compatible way","Dismiss the spiritual interpretation as unscientific","Insist on the biomedical model exclusively","Refuse to treat until the client accepts Western medical views"], correctIndex: 0, rationale: "Cultural humility requires respecting diverse understandings of addiction. Many effective treatment approaches (including 12-step programs) incorporate spiritual elements. Integration rather than replacement is key.", difficulty: 2, category: "Cultural Competence", topic: "Spiritual Beliefs" },
  { id: "cac-669", stem: "A client in methadone maintenance complains of excessive sedation. The MOST appropriate clinical response is:", options: ["Assess for medication interactions, evaluate dose appropriateness, check for concurrent substance use, and consider dose adjustment","Tell the client this is normal and will not change","Immediately discontinue methadone","Ignore the complaint as drug-seeking behavior"], correctIndex: 0, rationale: "Excessive sedation may indicate too-high dose, medication interactions, concurrent benzodiazepine/alcohol use, or medical conditions. Thorough assessment guides safe dose adjustment or identification of contributing factors.", difficulty: 3, category: "Pharmacology", topic: "Medication Management" },
  { id: "cac-670", stem: "The Recovery-Oriented Systems of Care (ROSC) model emphasizes:", options: ["A person-centered, strengths-based continuum of care that supports long-term recovery beyond acute treatment","Short-term, episode-based treatment only","Clinician-directed treatment without client input","Exclusive reliance on 12-step programs"], correctIndex: 0, rationale: "ROSC represents a paradigm shift from acute care to chronic care management of addiction, emphasizing community-based recovery support services, peer support, and systems that sustain long-term recovery.", difficulty: 3, category: "Theories of Addiction", topic: "Recovery Systems" },
  { id: "cac-671", stem: "A client with opioid use disorder becomes pregnant during buprenorphine treatment. The recommendation is:", options: ["Continue buprenorphine (often transitioning to buprenorphine mono-product without naloxone) as medication-assisted treatment improves outcomes for both mother and baby","Immediately taper and discontinue all medication","Switch to naltrexone for the duration of pregnancy","Discontinue all treatment until after delivery"], correctIndex: 0, rationale: "Continued MAT during pregnancy reduces illicit opioid use, improves prenatal care engagement, and reduces fetal exposure to cycles of intoxication/withdrawal. Buprenorphine mono-product is often preferred.", difficulty: 3, category: "Pharmacology", topic: "Special Populations" },
  { id: "cac-672", stem: "The primary purpose of aftercare or continuing care planning is:", options: ["Supporting sustained recovery through ongoing services, community connections, and relapse prevention after primary treatment","Generating revenue for the treatment facility","Satisfying regulatory requirements only","Providing a structured daily schedule indefinitely"], correctIndex: 0, rationale: "Continuing care bridges the gap between formal treatment and independent recovery. Research shows that participation in continuing care significantly improves long-term outcomes and reduces relapse rates.", difficulty: 1, category: "Counseling Fundamentals", topic: "Continuing Care" },
  { id: "cac-673", stem: "SMART Recovery differs from traditional 12-step programs primarily by:", options: ["Using a science-based, cognitive-behavioral approach with four-point program focusing on motivation, coping with urges, problem solving, and lifestyle balance","Requiring belief in a higher power","Being led by addiction medicine physicians","Prohibiting discussion of personal experiences"], correctIndex: 0, rationale: "SMART (Self-Management and Recovery Training) uses CBT and REBT principles. Its four points are: building motivation, coping with urges, managing thoughts/feelings/behaviors, and living a balanced life.", difficulty: 2, category: "Treatment Modalities", topic: "Mutual Aid Groups" },
  { id: "cac-674", stem: "When a counselor is subpoenaed to testify about a client's substance use treatment, 42 CFR Part 2 requires:", options: ["The counselor may not disclose information without a specific court order that meets 42 CFR Part 2 requirements, which are stricter than a subpoena alone","Immediate disclosure of all treatment records","Disclosure with the client's verbal permission only","Refusal under all circumstances, even with a proper court order"], correctIndex: 0, rationale: "Under 42 CFR Part 2, a subpoena alone is insufficient. A court order meeting specific Part 2 requirements (good cause hearing) is needed. This provides greater protection than HIPAA's subpoena provisions.", difficulty: 3, category: "Ethics", topic: "Confidentiality" },
  { id: "cac-675", stem: "Xylazine ('tranq') is increasingly found in the illicit drug supply. Counselors should know that:", options: ["Xylazine is a veterinary sedative not reversed by naloxone that causes severe skin ulceration at injection sites","Xylazine is an opioid that responds fully to naloxone","Xylazine only affects animals and has no effects on humans","Xylazine enhances the safety of other drugs when combined"], correctIndex: 0, rationale: "Xylazine is an alpha-2 adrenergic agonist (not an opioid) increasingly added to fentanyl. It causes prolonged sedation not reversible by naloxone, respiratory depression, bradycardia, and severe necrotic skin wounds.", difficulty: 3, category: "Substance Use Disorders", topic: "Emerging Substances" },
  { id: "cac-676", stem: "The technique of 'functional analysis' in CBT for addiction involves:", options: ["Examining the antecedents, behavior, and consequences of substance use episodes to identify patterns and triggers","Analyzing the client's personality functioning","Assessing cognitive IQ and executive functioning","Evaluating the client's physical health status"], correctIndex: 0, rationale: "Functional analysis (ABC model) identifies triggers/antecedents, the substance use behavior, and reinforcing consequences. This helps clients understand their use patterns and develop alternative responses.", difficulty: 2, category: "Treatment Modalities", topic: "CBT Techniques" },
  { id: "cac-677", stem: "A counselor who practices 'cultural humility' demonstrates:", options: ["Ongoing self-reflection about personal biases, a commitment to lifelong learning about diverse cultures, and recognition of power imbalances","Belief that their own cultural perspective is superior","Assumption that completing one diversity training is sufficient","Treating all clients identically regardless of cultural background"], correctIndex: 0, rationale: "Cultural humility goes beyond cultural competence to include continuous self-examination, recognition of cultural limitations, willingness to learn from clients, and addressing power imbalances in the therapeutic relationship.", difficulty: 2, category: "Cultural Competence", topic: "Cultural Humility" },
  { id: "cac-678", stem: "Withdrawal from which class of substances typically includes flu-like symptoms, muscle aches, diarrhea, and insomnia but is generally not life-threatening?", options: ["Opioids","Alcohol","Benzodiazepines","Barbiturates"], correctIndex: 0, rationale: "Opioid withdrawal, while intensely uncomfortable (myalgias, diarrhea, lacrimation, rhinorrhea, insomnia, dysphoria), is generally not life-threatening in otherwise healthy adults, unlike alcohol or sedative-hypnotic withdrawal.", difficulty: 2, category: "Substance Use Disorders", topic: "Withdrawal Syndromes" },
  { id: "cac-679", stem: "The primary goal of psychoeducation in addiction treatment is to:", options: ["Provide clients and families with knowledge about addiction, recovery, and related topics to support informed decision-making","Replace individual and group therapy entirely","Entertain clients during downtime in treatment","Satisfy accreditation requirements without clinical value"], correctIndex: 0, rationale: "Psychoeducation empowers clients with evidence-based information about the nature of addiction, effects of substances, coping strategies, and recovery processes, supporting informed treatment participation.", difficulty: 1, category: "Treatment Modalities", topic: "Psychoeducation" },
  { id: "cac-680", stem: "A counselor providing services via telehealth to clients with substance use disorders should:", options: ["Ensure HIPAA-compliant technology, verify client location, have a safety plan for emergencies, and maintain documentation standards","Use any video platform including social media","Lower documentation standards since sessions are virtual","Only provide telehealth to clients who are already stable in recovery"], correctIndex: 0, rationale: "Telehealth in addiction treatment requires HIPAA-compliant platforms, knowing the client's physical location for emergencies, maintaining confidentiality standards, and having protocols for crisis situations.", difficulty: 2, category: "Ethics", topic: "Telehealth" },
  { id: "cac-681", stem: "The 'disease of isolation' concept in recovery literature suggests that:", options: ["Social disconnection is both a contributing factor and a consequence of addiction, and recovery requires rebuilding social connections","Addiction is a communicable disease spread through social contact","Clients in recovery should isolate from all people","Physical isolation is the best treatment for addiction"], correctIndex: 0, rationale: "Addiction often involves progressive social withdrawal and isolation. Recovery emphasizes rebuilding authentic social connections, which serve as protective factors against relapse.", difficulty: 1, category: "Theories of Addiction", topic: "Social Factors" },
  { id: "cac-682", stem: "When conducting a group therapy session, the ideal group size for an interpersonal process group is:", options: ["7-10 members","2-3 members","20-25 members","50+ members"], correctIndex: 0, rationale: "Process groups function best with 7-10 members, allowing sufficient interaction variety while maintaining intimacy and ensuring each member has opportunity to participate. Smaller groups lack diversity; larger groups limit individual participation.", difficulty: 2, category: "Group Therapy", topic: "Group Structure" },
  { id: "cac-683", stem: "A client taking disulfiram should be warned to avoid:", options: ["All products containing alcohol including mouthwash, cough syrup, hand sanitizer, and certain foods","Only beer and wine","Only hard liquor","Only drinks with high alcohol content"], correctIndex: 0, rationale: "Disulfiram reacts with any alcohol, including in mouthwash, cough syrup, cooking wine, sauces, hand sanitizer (absorbed through skin), and vinegar-based products. Even small amounts can trigger the reaction.", difficulty: 2, category: "Pharmacology", topic: "Patient Education" },
  { id: "cac-684", stem: "Research on adverse childhood experiences (ACEs) and addiction shows that:", options: ["Higher ACE scores are associated with significantly increased risk of developing substance use disorders in adulthood","ACEs have no relationship to later substance use","Only physical abuse is a relevant ACE for addiction risk","ACEs only affect mental health, not substance use"], correctIndex: 0, rationale: "The landmark ACE study (Felitti et al.) demonstrated a strong dose-response relationship between childhood adversity and adult substance use, with each additional ACE increasing risk of early initiation and problematic use.", difficulty: 2, category: "Theories of Addiction", topic: "Risk Factors" },
  { id: "cac-685", stem: "A client on buprenorphine reports taking a full opioid agonist (heroin) and not feeling its effects. This is because:", options: ["Buprenorphine has high receptor affinity and blocks other opioids from binding effectively","Buprenorphine enhances the effects of other opioids","The heroin was not actually heroin","Buprenorphine only works on non-opioid receptors"], correctIndex: 0, rationale: "Buprenorphine's high binding affinity at mu-opioid receptors effectively blocks the effects of other opioids. This 'opioid blockade' effect is one of its therapeutic mechanisms in treating opioid use disorder.", difficulty: 3, category: "Pharmacology", topic: "Pharmacodynamics" },
  { id: "cac-686", stem: "In addiction treatment, the term 'step-down' refers to:", options: ["Transitioning from a more intensive to a less intensive level of care as the client progresses","Reducing medication dosage","Decreasing the counselor's involvement without the client's knowledge","Removing privileges as a consequence for rule violations"], correctIndex: 0, rationale: "Step-down is the planned transition along the continuum of care (e.g., residential to IOP to outpatient) as the client demonstrates progress, stability, and ability to function with less intensive support.", difficulty: 1, category: "Clinical Assessment", topic: "Level of Care" },
  { id: "cac-687", stem: "A counselor who maintains dual relationships by also socializing with clients outside of treatment is violating which ethical standard?", options: ["Professional boundaries designed to protect the therapeutic relationship and prevent exploitation","Only financial regulations","No ethical standards, as socializing builds rapport","Insurance billing requirements"], correctIndex: 0, rationale: "Dual relationships (having another relationship with a client beyond the professional one) create conflicts of interest, potential for exploitation, and compromise professional objectivity and the therapeutic relationship.", difficulty: 1, category: "Ethics", topic: "Dual Relationships" },
  { id: "cac-688", stem: "The concept of 'emotional sobriety' extends beyond physical abstinence to include:", options: ["The ability to manage emotions, maintain healthy relationships, and cope with life's challenges without substances","Never experiencing negative emotions","Complete emotional numbness","Suppressing all feelings"], correctIndex: 0, rationale: "Emotional sobriety, a concept attributed to Bill Wilson, involves developing emotional maturity, distress tolerance, and the ability to experience and manage the full range of emotions without chemical assistance.", difficulty: 2, category: "Theories of Addiction", topic: "Recovery Concepts" },
  { id: "cac-689", stem: "When treating methamphetamine use disorder, which statement about pharmacological treatment is accurate?", options: ["There are currently no FDA-approved medications specifically for methamphetamine use disorder","Naltrexone is FDA-approved for methamphetamine use disorder","Methadone is the standard treatment for methamphetamine addiction","Antabuse (disulfiram) is effective for methamphetamine use"], correctIndex: 0, rationale: "Unlike opioid and alcohol use disorders, there are currently no FDA-approved medications for stimulant use disorders. Behavioral treatments (CM, CBT, Matrix Model) remain the primary evidence-based approaches.", difficulty: 2, category: "Pharmacology", topic: "Treatment Limitations" },
  { id: "cac-690", stem: "In reality therapy (choice theory) applied to addiction counseling, the emphasis is on:", options: ["Present behavior and taking responsibility for choices, focusing on what the client can control","Analyzing unconscious motivations from early childhood","Environmental determinism where behavior is controlled by external forces","Pharmacological management as the sole treatment approach"], correctIndex: 0, rationale: "Reality therapy (Glasser) emphasizes current behavior, personal choice, responsibility, and meeting basic needs. It helps clients evaluate whether their current behavior (including substance use) is effectively meeting their needs.", difficulty: 3, category: "Treatment Modalities", topic: "Reality Therapy" },
  { id: "cac-691", stem: "A counselor's caseload management should consider:", options: ["Client acuity, session frequency, documentation requirements, supervision needs, and professional self-care","Only the total number of clients regardless of complexity","Financial revenue targets exclusively","How many clients the counselor's colleagues carry"], correctIndex: 0, rationale: "Effective caseload management balances multiple factors including client severity, required contact hours, administrative duties, training/supervision time, and counselor well-being to prevent burnout and ensure quality care.", difficulty: 2, category: "Counseling Fundamentals", topic: "Professional Practice" },
  { id: "cac-692", stem: "The concept of 'social determinants of health' is relevant to addiction treatment because:", options: ["Factors like poverty, housing instability, lack of education, and food insecurity significantly influence substance use initiation, progression, and recovery outcomes","Social factors are irrelevant to addiction","Only biological factors determine addiction outcomes","Treatment outcomes are solely dependent on individual motivation"], correctIndex: 0, rationale: "Social determinants (economic stability, education, social context, healthcare access, neighborhood environment) profoundly impact vulnerability to addiction and the ability to achieve and sustain recovery.", difficulty: 2, category: "Theories of Addiction", topic: "Social Determinants" },
  { id: "cac-693", stem: "When a client with an intellectual disability presents for addiction treatment, the counselor should:", options: ["Adapt treatment approaches using concrete language, visual aids, repetition, and shorter sessions while maintaining treatment integrity","Refuse treatment because the client cannot benefit","Use only pharmacological approaches","Apply identical approaches used with all other clients without modification"], correctIndex: 0, rationale: "Individuals with intellectual disabilities can benefit from adapted addiction treatment. Modifications include simpler language, visual learning aids, more frequent shorter sessions, and concrete skill practice.", difficulty: 2, category: "Special Populations", topic: "Intellectual Disability" },
  { id: "cac-694", stem: "The primary mechanism by which nicotine produces dependence is:", options: ["Stimulation of nicotinic acetylcholine receptors in the ventral tegmental area, increasing dopamine release in the nucleus accumbens","Blocking serotonin reuptake","Inhibiting MAO enzymes exclusively","Acting on opioid receptors"], correctIndex: 0, rationale: "Nicotine binds to nicotinic acetylcholine receptors (nAChRs) in the VTA, stimulating dopamine release in the nucleus accumbens. This rapid reinforcement cycle, combined with metabolic tolerance, drives compulsive use.", difficulty: 3, category: "Substance Use Disorders", topic: "Nicotine" },
  { id: "cac-695", stem: "A counselor who works in a correctional facility should be particularly aware that:", options: ["Incarcerated individuals have extremely high overdose risk immediately following release due to reduced tolerance","Incarceration permanently eliminates substance use problems","Inmates cannot benefit from addiction treatment","Post-release relapse is rare among formerly incarcerated individuals"], correctIndex: 0, rationale: "The first two weeks post-release represent the highest overdose risk period due to loss of tolerance during incarceration. Continuity of care, naloxone distribution, and MAT at release are critical interventions.", difficulty: 2, category: "Special Populations", topic: "Criminal Justice" },
  { id: "cac-696", stem: "The therapeutic factor of 'catharsis' in group therapy involves:", options: ["Emotional release and expression of feelings in a supportive group environment","Teaching skills through lecture format","Medication management within the group setting","Avoiding emotional expression to maintain group stability"], correctIndex: 0, rationale: "Catharsis (Yalom) involves the release of strong emotions in the safety of the group. While catharsis alone is not sufficient for change, combined with cognitive understanding, it contributes to therapeutic progress.", difficulty: 2, category: "Group Therapy", topic: "Therapeutic Factors" },
  { id: "cac-697", stem: "A client's employer contacts the treatment facility requesting confirmation that the client is enrolled in treatment. Without the client's written consent, the program should:", options: ["Neither confirm nor deny the client's participation in the program","Confirm enrollment but provide no other details","Deny the client is in treatment to protect them","Provide a full treatment update to the employer"], correctIndex: 0, rationale: "Under 42 CFR Part 2, a substance use treatment program cannot acknowledge that a person is a patient without their written consent. Even confirmation of enrollment constitutes a prohibited disclosure.", difficulty: 2, category: "Ethics", topic: "Confidentiality" },
  { id: "cac-698", stem: "The 'pink cloud' phenomenon in early recovery describes:", options: ["A period of euphoria and overconfidence that can lead to complacency about recovery efforts","Respiratory symptoms from smoking cessation","A visual hallucination indicating psychiatric emergency","The physical flushing that occurs during alcohol withdrawal"], correctIndex: 0, rationale: "The 'pink cloud' is a period of heightened well-being in early recovery that can lead to overconfidence, minimization of the work required, and vulnerability to relapse when the euphoria fades.", difficulty: 2, category: "Relapse Prevention", topic: "Early Recovery" },
  { id: "cac-699", stem: "Peer recovery support specialists contribute to treatment by:", options: ["Sharing lived experience of recovery to provide hope, practical guidance, and peer-based social support","Replacing licensed counselors in all treatment functions","Prescribing medications based on personal experience","Providing individual psychotherapy independently"], correctIndex: 0, rationale: "Peer specialists leverage their personal recovery experience to build rapport, provide role modeling, offer practical recovery support, and bridge the gap between professional treatment and community-based recovery.", difficulty: 1, category: "Treatment Modalities", topic: "Peer Support" },
  { id: "cac-700", stem: "When evaluating the effectiveness of an addiction treatment program, which outcome measure is MOST meaningful?", options: ["Sustained recovery indicators including reduced substance use, improved functioning, and quality of life at follow-up","Number of admissions processed per month","Total revenue generated by the program","Length of time clients spend in treatment regardless of outcome"], correctIndex: 0, rationale: "Meaningful outcomes include reductions in substance use, improved health, social functioning, employment, reduced criminal behavior, and quality of life measured at follow-up intervals, not just during treatment.", difficulty: 2, category: "Counseling Fundamentals", topic: "Program Evaluation" }
];
